import {AsYouType, parsePhoneNumberFromString, CountryCode} from 'libphonenumber-js';
import * as Haptics from 'expo-haptics';

type Country = {code: CountryCode; name: string; dial: string; flag: string};
const COUNTRIES: Country[] = [{code:'US', name:'United States', dial:'+1', flag:'🇺🇸'}, {code:'GB', name:'United Kingdom', dial:'+44', flag:'🇬🇧'}, {code:'IL', name:'Israel', dial:'+972', flag:'🇮🇱'}, {code:'DE', name:'Germany', dial:'+49', flag:'🇩🇪'}];

type Props = {value: string; onChange: (formatted: string, e164: string, valid: boolean) => void; onPickCountry: () => void; country: Country};
export function PhoneInput({value, onChange, onPickCountry, country}: Props) {
  const flagScale = useSharedValue(1);
  React.useEffect(() => { flagScale.value = withSequence(withSpring(1.2, {damping: 10, stiffness: 280}), withSpring(1, {damping: 14, stiffness: 240})); }, [country.code]);
