  return (<View style={s.field}><Pressable onPress={() => { Haptics.selectionAsync(); onPickCountry(); }} style={s.country}><Animated.Text style={[s.flag, flagStyle]}>{Platform.OS === 'ios' ? country.flag : country.code}</Animated.Text><Text style={s.dial}>{country.dial}</Text><Text style={s.chevron}>{'\u25BE'}</Text></Pressable><TextInput value={value} onChangeText={handleChange} placeholder='Phone number' placeholderTextColor='#48484A' keyboardType='phone-pad' textContentType='telephoneNumber' autoComplete='tel' style={s.input}/></View>);
}
