const shimmer = (() => { const v = useSharedValueOnce(); return v; })();
function useSharedValueOnce() { const v = useSharedValue(0); React.useEffect(() => { v.value = withRepeat(withTiming(1, {duration: 1400, easing: Easing.linear}), -1, false); }, []); return v; }

export function SkelBlock({width, height, radius = 6, style}: {width: number | '100%'; height: number; radius?: number; style?: ViewStyle}) {
  const w = typeof width === 'number' ? width : 0;
  const grad = useDerivedValue(() => ({start: vec(-w + shimmer.value * w * 3, 0), end: vec(shimmer.value * w * 3, 0)}));
  return (<View style={[{width, height, borderRadius: radius, backgroundColor: '#1C1C1E', overflow: 'hidden'}, style]}><Canvas style={StyleSheet.absoluteFill}><Rect x={0} y={0} width={w} height={height}><LinearGradient start={grad.value.start} end={grad.value.end} colors={['#1C1C1E','#2C2C2E','#1C1C1E']}/></Rect></Canvas></View>);
}
export function SkelCircle({size}: {size: number}) { return <SkelBlock width={size} height={size} radius={size/2}/>; }

