import React, {useEffect, useState, useCallback} from 'react';
import {StyleSheet, View, Pressable, Text, useWindowDimensions} from 'react-native';
import {FlashList} from '@shopify/flash-list';
import {Image} from 'expo-image';
import * as MediaLibrary from 'expo-media-library';
import Animated, {useSharedValue, useAnimatedStyle, withSpring} from 'react-native-reanimated';
import {useSyncExternalStore} from 'react';
import * as Haptics from 'expo-haptics';

const order: string[] = []; const listeners = new Map<string, Set<() => void>>();
function sub(k: string, cb: () => void) { let set = listeners.get(k); if (!set) { set = new Set(); listeners.set(k, set); } set.add(cb); return () => set!.delete(cb); }
function emit(k: string) { listeners.get(k)?.forEach(cb => cb()); }
function useSelection(id: string) { return useSyncExternalStore(cb => sub(id, cb), () => order.indexOf(id)); }
function toggle(id: string, max: number) { const idx = order.indexOf(id); if (idx >= 0) { order.splice(idx, 1); emit(id); order.forEach(x => emit(x)); } else { if (order.length >= max) return false; order.push(id); emit(id); } return true; }

export function PhotoPicker({maxSelection = 10, onDone}: {maxSelection?: number; onDone: (ids: string[]) => void}) {
  const {width: SW} = useWindowDimensions();
  const cols = SW > 700 ? 5 : 3;
  const colW = (SW - (cols + 1) * 2) / cols;
  const [assets, setAssets] = useState<MediaLibrary.Asset[]>([]);
  useEffect(() => { (async () => { const {status} = await MediaLibrary.requestPermissionsAsync(); if (status !== 'granted') return; const res = await MediaLibrary.getAssetsAsync({first: 200, sortBy: ['creationTime']}); setAssets(res.assets); })(); }, []);
  const renderItem = useCallback(({item}: {item: MediaLibrary.Asset}) => (<Cell asset={item} colW={colW} max={maxSelection}/>), [colW, maxSelection]);
  return (<View style={{flex:1, backgroundColor:'#000'}}><FlashList data={assets} numColumns={cols} renderItem={renderItem} keyExtractor={i => i.id} estimatedItemSize={colW}/><Pressable onPress={() => onDone([...order])} style={s.done}><Text style={s.doneText}>Done ({order.length})</Text></Pressable></View>);
}

function Cell({asset, colW, max}: {asset: MediaLibrary.Asset; colW: number; max: number}) {
  const idx = useSelection(asset.id);
  const scale = useSharedValue(idx >= 0 ? 1 : 0);
  React.useEffect(() => { scale.value = withSpring(idx >= 0 ? 1 : 0, {damping: 14, stiffness: 280}); }, [idx]);
  const badgeStyle = useAnimatedStyle(() => ({transform: [{scale: scale.value}]}));
  const onPress = () => { Haptics.selectionAsync(); toggle(asset.id, max); };
  return (<Pressable onPress={onPress} style={{width: colW, height: colW, padding: 1}}><Image source={asset.uri} style={{width: colW - 2, height: colW - 2, backgroundColor: '#1C1C1E'}} contentFit='cover' cachePolicy='memory'/><Animated.View style={[s.badge, badgeStyle]}>{idx >= 0 && <Text style={s.badgeText}>{idx + 1}</Text>}</Animated.View>{idx >= 0 && <View style={s.selectedOverlay}/>}</Pressable>);
}
const s = StyleSheet.create({badge:{position:'absolute', top:6, right:6, width:24, height:24, borderRadius:12, backgroundColor:'#0A84FF', alignItems:'center', justifyContent:'center'}, badgeText:{color:'#fff', fontSize:13, fontWeight:'700'}, selectedOverlay:{...StyleSheet.absoluteFillObject, backgroundColor:'rgba(10,132,255,0.2)', borderWidth:3, borderColor:'#0A84FF'}, done:{position:'absolute', bottom:30, right:16, backgroundColor:'#0A84FF', paddingHorizontal:20, paddingVertical:12, borderRadius:24}, doneText:{color:'#fff', fontSize:16, fontWeight:'600'}});

