import React, {useState, useCallback} from 'react';
import {StyleSheet, View, Text, Pressable, AccessibilityInfo} from 'react-native';
import {Image} from 'expo-image';

export function ProfileScreen({user}: {user: {name: string; handle: string; avatar: string; followers: number; following: number; bio: string}}) {
  const [tab, setTab] = useState<'posts'|'saved'|'liked'>('posts');
  const switchTab = useCallback((next: typeof tab) => {
    setTab(next);
    AccessibilityInfo.announceForAccessibility(`${next} tab selected`);
  }, []);
  return (
    <View style={s.root}>
      <View accessible accessibilityRole="header" accessibilityLabel={`${user.name}, ${user.handle}`} style={s.header}>
        <Image source={user.avatar} style={s.avatar} accessibilityIgnoresInvertColors />
        <View style={s.headerText}>
          <Text style={s.name}>{user.name}</Text>
          <Text style={s.handle}>{user.handle}</Text>
        </View>
        <Pressable accessibilityRole="button" accessibilityLabel="Edit profile" hitSlop={8} style={s.editBtn}>
          <Text style={s.editText}>Edit</Text>
        </Pressable>
      </View>
      <View accessible accessibilityRole="summary" accessibilityLabel={`${user.followers} followers, ${user.following} following`} style={s.stats}>
        <Stat label="Followers" value={user.followers} />
        <Stat label="Following" value={user.following} />
      </View>
      <Text accessibilityRole="text" style={s.bio}>{user.bio}</Text>
      <View accessibilityRole="tablist" style={s.tabs}>
        {(['posts','saved','liked'] as const).map((next) => (
          <Pressable
            key={next}
            onPress={() => switchTab(next)}
            accessibilityRole="tab"
            accessibilityState={{selected: tab === next}}
            accessibilityLabel={`${next} tab`}
            hitSlop={8}
            style={[s.tab, tab === next && s.tabActive]}
          >
            <Text style={[s.tabText, tab === next && s.tabTextActive]}>{next}</Text>
          </Pressable>
        ))}
      </View>
      <View accessibilityRole="tabpanel" accessibilityLabel={`${tab} content`} style={s.content}>
        <Text style={s.placeholder}>Content for {tab}</Text>
      </View>
    </View>
  );
}

function Stat({label, value}: {label: string; value: number}) {
  return (
    <View style={s.stat} importantForAccessibility="no-hide-descendants">
      <Text style={s.statValue}>{value}</Text>
      <Text style={s.statLabel}>{label}</Text>
    </View>
  );
}

