import {useCallback, useRef} from 'react';
import {Image} from 'expo-image';
import {ViewToken} from '@shopify/flash-list';
export function useFeedPrefetch<T extends {id: string; uri: string}>(items: T[], ahead = 5) { const prefetchedRef = useRef<Set<string>>(new Set()); const onViewableItemsChanged = useCallback(({viewableItems}: {viewableItems: ViewToken[]}) => { if (viewableItems.length === 0) return; const lastVisibleIndex = Math.max(...viewableItems.map(v => v.index ?? 0)); for (let i = lastVisibleIndex + 1; i <= Math.min(items.length - 1, lastVisibleIndex + ahead); i++) { const it = items[i]; if (it && !prefetchedRef.current.has(it.id)) { prefetchedRef.current.add(it.id); Image.prefetch(it.uri, 'memory-disk'); }}}, [items, ahead]); return {onViewableItemsChanged}; }

