  const pinch = Gesture.Pinch().onStart(() => { savedScale.value = scale.value; }).onUpdate(e => { scale.value = Math.max(0.5, Math.min(5, savedScale.value * e.scale)); }).onEnd(() => { scale.value = withSpring(Math.max(1, scale.value), {damping: 18, stiffness: 220}); });
