import React, {useCallback, useRef, useState} from 'react';
import {StyleSheet, View} from 'react-native';
import {FlashList} from '@shopify/flash-list';
import {SkelBlock} from './Skeleton';

type Row<T> = {type: 'item'; data: T} | {type: 'skeleton'; key: string};
type Props<T> = {fetch: (cursor: string | null) => Promise<{items: T[]; nextCursor: string | null}>; renderItem: (item: T) => React.ReactNode; estimatedItemSize: number; keyExtractor: (item: T) => string};

export function InfiniteList<T>({fetch, renderItem, estimatedItemSize, keyExtractor}: Props<T>) {
  const [items, setItems] = useState<T[]>([]);
  const [skeletonCount, setSkeletonCount] = useState(5);
  const cursorRef = useRef<string | null>(null);
  const loadingRef = useRef(false);
  const doneRef = useRef(false);
  const load = useCallback(async () => { if (loadingRef.current || doneRef.current) return; loadingRef.current = true; setSkeletonCount(5); try { const res = await fetch(cursorRef.current); setItems(prev => [...prev, ...res.items]); cursorRef.current = res.nextCursor; if (!res.nextCursor) doneRef.current = true; setSkeletonCount(0); } finally { loadingRef.current = false; }}, [fetch]);
  React.useEffect(() => { load(); }, []);
  const data: Row<T>[] = [...items.map(d => ({type: 'item' as const, data: d})), ...Array.from({length: skeletonCount}, (_, i) => ({type: 'skeleton' as const, key: `sk-${items.length}-${i}`}))];
  return (<FlashList data={data} renderItem={({item}) => item.type === 'skeleton' ? <SkeletonRow/> : <View>{renderItem(item.data)}</View>} estimatedItemSize={estimatedItemSize} keyExtractor={(item, i) => item.type === 'item' ? keyExtractor(item.data) : item.key} onEndReached={load} onEndReachedThreshold={0.5} getItemType={item => item.type}/>);
}
function SkeletonRow() { return (<View style={{padding: 16, gap: 8}}><SkelBlock width={'100%'} height={16}/><SkelBlock width={240} height={12}/></View>); }

