import React, {useEffect} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Rect, Path, Skia, ClipOp, Group} from '@shopify/react-native-skia';
import {useSharedValue, withRepeat, withTiming, Easing, useDerivedValue} from 'react-native-reanimated';

export function StripedProgressBar({progress, width, height = 12, paused = false}: {progress: number; width: number; height?: number; paused?: boolean}) {
  const offset = useSharedValue(0);
  useEffect(() => { offset.value = withRepeat(withTiming(16, {duration: paused ? 4000 : 800, easing: Easing.linear}), -1, false); }, [paused]);
  const stripePath = useDerivedValue(() => { const p = Skia.Path.Make(); const sw = 8; for (let x = -height + offset.value; x < width + height; x += sw * 2) { p.moveTo(x, 0); p.lineTo(x + height, height); p.lineTo(x + height + sw, height); p.lineTo(x + sw, 0); p.close(); } return p; });
  const fillW = useDerivedValue(() => Math.max(0, Math.min(1, progress)) * width);
  const clipPath = useDerivedValue(() => { const p = Skia.Path.Make(); p.addRect({x: 0, y: 0, width: fillW.value, height}); return p; });
  return (<View style={{width, height, borderRadius: height/2, overflow: 'hidden', backgroundColor: '#1C1C1E'}}><Canvas style={StyleSheet.absoluteFill}><Group clip={clipPath}><Rect x={0} y={0} width={width} height={height} color='#0A84FF'/><Path path={stripePath} color='rgba(255,255,255,0.18)'/></Group></Canvas></View>);
}

